if (!defined('CLI_SCRIPT')) { define('CLI_SCRIPT', true); }
require('/www/moodle/config.php');
require_once($CFG->libdir . '/filestorage/file_storage.php');
try {
    $admin = get_admin();
    \core\session\manager::set_user($admin);
    $usercontext = \context_user::instance($admin->id);
    $sourcepath = $CFG->dirroot . '/privacy/tests/fixtures/logo.png';
    if (!file_exists($sourcepath)) {
        echo "Source image not found at {$sourcepath}\n";
    } else {
        $fs = get_file_storage();
        $draftitemid = file_get_unused_draft_itemid();
        $filerecord = [
            'contextid' => $usercontext->id,
            'component' => 'user',
            'filearea'  => 'draft',
            'itemid'    => $draftitemid,
            'filepath'  => '/',
            'filename'  => 'logo.png',
        ];
        $draftfile = $fs->create_file_from_pathname($filerecord, $sourcepath);
        $contenttype = new \contenttype_image\contenttype(\context_system::instance());
        $content = $contenttype->create_content((object)['name' => 'logo.png']);
        $content->import_file($draftfile);
        echo "Imported logo.png into system content bank (contentid={$content->get_id()})\n";
    }
} catch (\Throwable $e) {
    echo 'ERROR: ' . $e->getMessage() . "\n";
}
